import heapq
from collections import defaultdict


class Twitter:
    def __init__(self):
        self.ts = 0
        self.tweets = defaultdict(list)  # uid -> [(neg_time, tweetId)]
        self.following = defaultdict(set)  # uid -> set of followees

    def postTweet(self, userId, tweetId):
        self.tweets[userId].append((-self.ts, tweetId))
        self.ts += 1

    def getNewsFeed(self, userId):
        heap = []
        candidates = [userId] + list(self.following[userId])
        for uid in candidates:
            lst = self.tweets[uid]
            if lst:
                idx = len(lst) - 1
                neg_t, tid = lst[idx]
                heapq.heappush(heap, (neg_t, tid, uid, idx))
        result = []
        while heap and len(result) < 10:
            neg_t, tid, uid, idx = heapq.heappop(heap)
            result.append(tid)
            if idx > 0:
                neg_t2, tid2 = self.tweets[uid][idx - 1]
                heapq.heappush(heap, (neg_t2, tid2, uid, idx - 1))
        return result

    def follow(self, followerId, followeeId):
        if followerId != followeeId:
            self.following[followerId].add(followeeId)

    def unfollow(self, followerId, followeeId):
        self.following[followerId].discard(followeeId)

