class Twitter {
    constructor() {
        this.ts = 0;
        this.tweets = new Map();
        this.following = new Map();
    }
    postTweet(userId, tweetId) {
        if (!this.tweets.has(userId)) this.tweets.set(userId, []);
        this.tweets.get(userId).push([this.ts++, tweetId]);
    }
    getNewsFeed(userId) {
        const candidates = [userId];
        if (this.following.has(userId)) {
            for (const f of this.following.get(userId)) candidates.push(f);
        }
        // collect all tweets from candidates, sort by ts desc, take 10
        const all = [];
        for (const uid of candidates) {
            const lst = this.tweets.get(uid) || [];
            for (const [t, tid] of lst) all.push([t, tid]);
        }
        all.sort((a, b) => b[0] - a[0]);
        return all.slice(0, 10).map(x => x[1]);
    }
    follow(followerId, followeeId) {
        if (followerId === followeeId) return;
        if (!this.following.has(followerId)) this.following.set(followerId, new Set());
        this.following.get(followerId).add(followeeId);
    }
    unfollow(followerId, followeeId) {
        if (this.following.has(followerId)) this.following.get(followerId).delete(followeeId);
    }
}
